#include <cstdio>
#include <cstdlib>
#include <omp.h>

#define BLOCK_SIZE 512

__attribute__((target(mounted))) void convolution_1D(float *N, float *M, float *P, int Mask_Width, int Width) {
    int n = omp_get_thread_num() + omp_get_team_num() * omp_get_num_threads();
    int total_threads = omp_get_num_threads() * omp_get_num_teams();
    int Mask_radius = Mask_Width / 2;

    for (int i = n; i < Width; i += total_threads) {
        float Pvalue = 0;
        for (int j = -Mask_radius; j <= Mask_radius; j++) {
            int d = i + j;
            if (d >= 0 && d < Width) {
                Pvalue += N[d] * M[Mask_radius - j];
            }
        }
        P[i] = Pvalue;
    }
}

int main(int argc, char **argv) {
    int Width = 1 << 20;
    int Mask_Width = 7;
    float *N = (float *)malloc(Width * sizeof(float));
    float *P = (float *)malloc(Width * sizeof(float));
    float *M = (float *)malloc(Mask_Width * sizeof(float));

    for (int i = 0; i < Mask_Width; i++) {
        M[i] = 1.0f;
    }
    for (int i = 0; i < Width; i++) {
        N[i] = 1.0f;
    }

    #pragma omp target data map(to: N[0:Width], M[0:Mask_Width]) map(from: P[0:Width])
    {
        #pragma omp target teams distribute parallel for thread_limit(BLOCK_SIZE)
        for (int i = 0; i < Width; i++) {
            float Pvalue = 0;
            int Mask_radius = Mask_Width / 2;
            for (int j = -Mask_radius; j <= Mask_radius; j++) {
                int d = i + j;
                if (d >= 0 && d < Width) {
                    Pvalue += N[d] * M[Mask_radius - j];
                }
            }
            P[i] = Pvalue;
        }
    }

    printf("P[0] = %f\n", P[0]);
    printf("P[Width-1] = %f\n", P[Width-1]);

    free(N);
    free(P);
    free(M);

    return 0;
}
